1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Step = { op: string; items: Item[] };
3	type Result = { premium: number };
4	type ScenarioInput = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	type ScenarioOutput = { results: Result[] };
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
15	const CURSED_SURCHARGE_PERCENT = 50;
16	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const LOYALTY_DISCOUNT_PERCENT = 20;
19	const LOYALTY_THRESHOLD_YEARS = 2;
20	const PROCESSING_FEE = 5;
21	
22	const addSurchargePercent = (amount: number, percent: number): number =>
23	  (amount * (100 + percent)) / 100;
24	
25	const addSurchargeIf = (amount: number, condition: boolean, percent: number): number =>
26	  condition ? addSurchargePercent(amount, percent) : amount;
27	
28	const applyDiscountIf = (amount: number, condition: boolean, percent: number): number =>
29	  condition ? (amount * (100 - percent)) / 100 : amount;
30	
31	const itemPremium = (item: Item): number => {
32	  const base = BASE_PREMIUMS[item.type];
33	  const withCursed = addSurchargeIf(base, item.cursed, CURSED_SURCHARGE_PERCENT);
34	  return addSurchargeIf(
35	    withCursed,
36	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
37	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
38	  );
39	};
40	
41	const sumItemPremiums = (items: Item[]): number =>
42	  items.reduce((sum, item) => sum + itemPremium(item), 0);
43	
44	const quotePremium = (items: Item[], yearsWithMHPCO: number): number => {
45	  const withFirstInsurance = addSurchargePercent(
46	    sumItemPremiums(items),
47	    FIRST_INSURANCE_SURCHARGE_PERCENT,
48	  );
49	  const withLoyalty = applyDiscountIf(
50	    withFirstInsurance,
51	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
52	    LOYALTY_DISCOUNT_PERCENT,
53	  );
54	  return withLoyalty + PROCESSING_FEE;
55	};
56	
57	export const runScenario = (input: ScenarioInput): ScenarioOutput => ({
58	  results: input.steps.map((step) => ({
59	    premium: quotePremium(step.items, input.customer.yearsWithMHPCO),
60	  })),
61	});
