const quotePremium = (items: Item[], yearsWithMHPCO: number, isFirstQuote: boolean): number => {
  const itemsTotal = sumItemPremiums(items);
  const withContractAdjustment = isFirstQuote
    ? addSurchargePercent(itemsTotal, FIRST_INSURANCE_SURCHARGE_PERCENT)
    : applyDiscountIf(itemsTotal, true, REPEAT_CONTRACT_DISCOUNT_PERCENT);
  const withLoyalty = applyDiscountIf(
    withContractAdjustment,
    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
    LOYALTY_DISCOUNT_PERCENT,
  );
  return withLoyalty + PROCESSING_FEE;
};

export const runScenario = (input: ScenarioInput): ScenarioOutput => ({
  results: input.steps.map((step, index) => ({
    premium: quotePremium(step.items, input.customer.yearsWithMHPCO, index === 0),
  })),
});
